import React, { useState, useEffect, useMemo } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  GoabText,
  GoabButton,
  GoabButtonGroup,
  GoabBadge,
  GoabTabs,
  GoabTab,
  GoabDivider,
  GoabFormItem,
  GoabTextArea,
  GoabSkeleton,
  GoabCallout
} from '@abgov/react-components';
import { usePageHeader } from '../contexts/PageHeaderContext';
import { Case, CaseNote } from '../types/Case';
import mockCases from '../data/mockCases.json';
import { formatDate, formatRelativeDate, isOverdue } from '../utils/dateUtils';
import { getStatusBadgeProps, getPriorityBadgeProps } from '../utils/badgeUtils';
import { mockFetch } from '../utils/mockApi';

export function CaseDetailPage() {
  const { caseId } = useParams<{ caseId: string }>();
  const navigate = useNavigate();
  const [caseData, setCaseData] = useState<Case | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState(0);
  const [newNote, setNewNote] = useState('');

  // Header actions
  const headerActions = useMemo(() => (
    <GoabButtonGroup gap="compact" alignment="end">
      <GoabButton type="secondary" size="compact">Edit</GoabButton>
      <GoabButton type="primary" size="compact">Update Status</GoabButton>
    </GoabButtonGroup>
  ), []);

  usePageHeader(caseData?.childName || 'Case Details', headerActions);

  // Fetch case data
  useEffect(() => {
    const loadCase = async () => {
      setIsLoading(true);
      const allCases = await mockFetch<Case[]>(mockCases as Case[]);
      const foundCase = allCases.find(c => c.id === caseId);
      setCaseData(foundCase || null);
      setIsLoading(false);
    };
    loadCase();
  }, [caseId]);

  // Add note handler
  const handleAddNote = () => {
    if (!newNote.trim() || !caseData) return;

    const note: CaseNote = {
      id: `note-${Date.now()}`,
      date: new Date().toISOString().split('T')[0],
      author: 'Current User',
      content: newNote
    };

    setCaseData({
      ...caseData,
      notes: [note, ...caseData.notes]
    });
    setNewNote('');
  };

  // Loading state
  if (isLoading) {
    return (
      <div style={{ maxWidth: '100%', overflow: 'hidden', paddingBottom: '32px' }}>
        <div className="clients-content-padding">
          <GoabSkeleton type="header" />
          <GoabSkeleton type="text" />
          <GoabSkeleton type="text" />
        </div>
      </div>
    );
  }

  // Not found state
  if (!caseData) {
    return (
      <div style={{ maxWidth: '100%', overflow: 'hidden', paddingBottom: '32px' }}>
        <div className="clients-content-padding">
          <GoabCallout type="emergency" heading="Case not found">
            The case {caseId} could not be found.
          </GoabCallout>
          <GoabButton mt="l" onClick={() => navigate('/cases')}>Back to Cases</GoabButton>
        </div>
      </div>
    );
  }

  const statusBadge = getStatusBadgeProps(caseData.status);
  const priorityBadge = getPriorityBadgeProps(caseData.priority);
  const overdue = isOverdue(caseData.dueDate) && caseData.status !== 'complete';

  return (
    <div style={{ maxWidth: '100%', overflow: 'hidden', paddingBottom: '32px' }}>
      <div className="clients-content-padding">
        {/* Status badges row */}
        <div style={{ marginBottom: '24px' }}>
          <div style={{ display: 'flex', gap: '12px', alignItems: 'center', marginBottom: '8px', flexWrap: 'wrap' }}>
            <GoabBadge type={statusBadge.type} content={statusBadge.content} />
            <GoabBadge type={priorityBadge.type} content={priorityBadge.content} />
            {caseData.isUrgent && <GoabBadge type="emergency" content="Urgent" />}
          </div>
          <GoabText size="body-s" color="secondary">Case ID: {caseData.id}</GoabText>
        </div>

        {/* Quick metadata grid */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '16px', marginBottom: '24px' }}>
          <div>
            <GoabText size="body-xs" color="secondary">Due Date</GoabText>
            <GoabText size="body-m" color={overdue ? 'emergency' : undefined} weight="bold">
              {formatDate(caseData.dueDate)}
            </GoabText>
            <GoabText size="body-xs" color="secondary">{formatRelativeDate(caseData.dueDate)}</GoabText>
          </div>
          <div>
            <GoabText size="body-xs" color="secondary">Assigned To</GoabText>
            <GoabText size="body-m" weight="bold">{caseData.assignedToName || 'Unassigned'}</GoabText>
          </div>
          <div>
            <GoabText size="body-xs" color="secondary">Created</GoabText>
            <GoabText size="body-m">{formatDate(caseData.createdDate)}</GoabText>
          </div>
          <div>
            <GoabText size="body-xs" color="secondary">Last Updated</GoabText>
            <GoabText size="body-m">{formatDate(caseData.lastUpdated)}</GoabText>
          </div>
        </div>

        <GoabDivider mb="l" />

        {/* Tabbed content */}
        <GoabTabs initialTab={activeTab} onChange={(e) => setActiveTab(e.detail.tab)}>
          <GoabTab heading="Details">
            <div style={{ padding: '24px 0' }}>
              {/* Section: Primary info */}
              <GoabText size="heading-s" mb="m">Child Information</GoabText>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px', marginBottom: '32px' }}>
                <div>
                  <GoabText size="body-xs" color="secondary">Name</GoabText>
                  <GoabText size="body-m">{caseData.childName}</GoabText>
                </div>
                <div>
                  <GoabText size="body-xs" color="secondary">Date of Birth</GoabText>
                  <GoabText size="body-m">{formatDate(caseData.childDateOfBirth)}</GoabText>
                </div>
              </div>

              {/* Section: Contact info */}
              <GoabText size="heading-s" mb="m">Parent/Guardian Information</GoabText>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
                <div>
                  <GoabText size="body-xs" color="secondary">Name</GoabText>
                  <GoabText size="body-m">{caseData.parentGuardian.name}</GoabText>
                </div>
                <div>
                  <GoabText size="body-xs" color="secondary">Relationship</GoabText>
                  <GoabText size="body-m">{caseData.parentGuardian.relationship}</GoabText>
                </div>
                <div>
                  <GoabText size="body-xs" color="secondary">Phone</GoabText>
                  <GoabText size="body-m">{caseData.parentGuardian.phone}</GoabText>
                </div>
                <div>
                  <GoabText size="body-xs" color="secondary">Email</GoabText>
                  <GoabText size="body-m">{caseData.parentGuardian.email}</GoabText>
                </div>
                <div style={{ gridColumn: 'span 2' }}>
                  <GoabText size="body-xs" color="secondary">Address</GoabText>
                  <GoabText size="body-m">
                    {caseData.parentGuardian.address.street}, {caseData.parentGuardian.address.city}, {caseData.parentGuardian.address.province} {caseData.parentGuardian.address.postalCode}
                  </GoabText>
                </div>
              </div>
            </div>
          </GoabTab>

          <GoabTab heading="Timeline">
            <div style={{ padding: '24px 0' }}>
              {caseData.events.length === 0 ? (
                <GoabText color="secondary">No events recorded yet.</GoabText>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  {caseData.events
                    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                    .map(event => (
                      <div key={event.id} style={{ borderLeft: '3px solid var(--goa-color-interactive-default)', paddingLeft: '16px' }}>
                        <GoabText size="body-xs" color="secondary">{formatDate(event.date)}</GoabText>
                        <GoabText size="body-m" weight="bold">
                          {event.type.replace('-', ' ').replace(/\b\w/g, l => l.toUpperCase())}
                        </GoabText>
                        <GoabText size="body-m">{event.description}</GoabText>
                        <GoabText size="body-xs" color="secondary">By {event.author}</GoabText>
                      </div>
                    ))}
                </div>
              )}
            </div>
          </GoabTab>

          <GoabTab heading="Notes">
            <div style={{ padding: '24px 0' }}>
              {/* Add note form */}
              <div style={{ marginBottom: '24px' }}>
                <GoabFormItem label="Add a note">
                  <GoabTextArea
                    name="newNote"
                    value={newNote}
                    placeholder="Enter your note here..."
                    rows={3}
                    onChange={(e) => setNewNote(e.detail.value)}
                  />
                </GoabFormItem>
                <GoabButton
                  type="primary"
                  size="compact"
                  mt="s"
                  disabled={!newNote.trim()}
                  onClick={handleAddNote}
                >
                  Add Note
                </GoabButton>
              </div>

              <GoabDivider mb="l" />

              {/* Notes list */}
              {caseData.notes.length === 0 ? (
                <GoabText color="secondary">No notes yet.</GoabText>
              ) : (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                  {caseData.notes
                    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())
                    .map(note => (
                      <div key={note.id} style={{ padding: '16px', backgroundColor: 'var(--goa-color-greyscale-100)', borderRadius: '4px' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                          <GoabText size="body-s" weight="bold">{note.author}</GoabText>
                          <GoabText size="body-xs" color="secondary">{formatDate(note.date)}</GoabText>
                        </div>
                        <GoabText size="body-m">{note.content}</GoabText>
                      </div>
                    ))}
                </div>
              )}
            </div>
          </GoabTab>
        </GoabTabs>
      </div>
    </div>
  );
}
